  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "answers": [
    {
      "summary": "当前围绕已选中的两个产品流生成候选提案：liquid-product-5 的下游连接缺失问题，以及 vapor-product-5 的温度规格缺失问题。",
      "issues": [
        {
          "code": "STREAM_DISCONNECTED",
          "message": "Liquid Product 未连接到任何下游消费者或出口汇，导致拓扑无效。",
          "severity": "error",
          "target": {
            "type": "stream",
            "id": "liquid-product-5"
          },
          "citations": [
            "diag-1",
            "flowdoc-stream-2",
            "snapshot-1"
          ]
        },
        {
          "code": "STREAM_SPEC_MISSING",
          "message": "Vapor Product 缺少温度规格。",
          "severity": "error",
          "target": {
            "type": "stream",
            "id": "vapor-product-5"
          },
          "citations": [
            "diag-2",
            "flowdoc-stream-3"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 Liquid Product 添加下游连接占位",
          "target": {
            "type": "stream",
            "id": "liquid-product-5"
          },
          "rationale": "诊断指出 liquid-product-5 没有连接到下游消费者或出口汇；当前快照显示求解状态为 invalid_topology。由于请求中没有提供明确的目标单元或出口汇，只能提出一个待确认的连接占位，而不是执行重连。",
          "patch": {
            "connection_placeholder": {
              "field": "target_unit_id",
              "placeholder": "TODO_SELECT_DOWNSTREAM_CONSUMER_OR_EXPORT_SINK",
              "note": "请确认 Liquid Product 应连接到的下游单元或出口汇。"
            }
          },
          "risk_level": "high",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-stream-2",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 Vapor Product 补充温度规格占位",
          "target": {
            "type": "stream",
            "id": "vapor-product-5"
          },
          "rationale": "诊断指出 vapor-product-5 缺少 temperature specification；当前文档中该流仅包含 pressure_kpa 规格，因此建议添加待确认的温度占位。",
          "patch": {
            "spec_placeholders": {
              "temperature_c": {
                "placeholder": "TODO_CONFIRM_TEMPERATURE_C",
                "note": "请确认 Vapor Product 的温度设定值。"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-stream-3"
          ]
        }
      ],
      "confidence": 0.82
    }
  ]
}
